func init() {
	if err := registerFont("Graffiti", fontGraffiti); err != nil {
		panic("ascii: failed to register Graffiti font: " + err.Error())
	}
	if err := registerFont("Standard", fontStandard); err != nil {
		panic("ascii: failed to register Standard font: " + err.Error())
	}
	if err := registerFont("Big", fontBig); err != nil {
		panic("ascii: failed to register Big font: " + err.Error())
	}
	if err := registerFont("Block", fontBlock); err != nil {
		panic("ascii: failed to register Block font: " + err.Error())
	}
	if err := registerFont("Shadow", fontShadow); err != nil {
		panic("ascii: failed to register Shadow font: " + err.Error())
	}
}
